import React, { useState } from 'react';
import { StyleSheet, View, Text, Button } from 'react-native';

const NetworkingModule = () => {
  const [apiResponse, setApiResponse] = useState(null);
  const [iotDeviceResponse, setIotDeviceResponse] = useState(null);

  const fetchFromAPI = async () => {
    try {
      const response = await fetch('https://api.example.com', {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer YOUR_API_TOKEN'
        }
      });
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      const data = await response.json();
      setApiResponse(data);
    } catch (error) {
      console.error('There has been a problem with your fetch operation:', error);
    }
  };

  const fetchFromIoTDevice = async () => {
    try {
      const response = await fetch('http://192.168.x.x', {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json'
        }
      });
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      const data = await response.json();
      setIotDeviceResponse(data);
    } catch (error) {
      console.error('There has been a problem with your fetch operation:', error);
    }
  };

  return (
    <View style={styles.container}>
      <Button title="Fetch from API" onPress={fetchFromAPI} />
      <Button title="Fetch from IoT Device" onPress={fetchFromIoTDevice} />
      {apiResponse && <Text>{JSON.stringify(apiResponse)}</Text>}
      {iotDeviceResponse && <Text>{JSON.stringify(iotDeviceResponse)}</Text>}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#fff',
  },
});

export default NetworkingModule;